def benchmark_load(model_name, fmt):
    start = time.time()
    if fmt == "pytorch":
        m = AutoModel.from_pretrained(model_name)
    elif fmt == "safetensors":
        m = AutoModel.from_pretrained(model_name, use_safetensors=True)
    elif fmt == "onnx":
        m = ORTModelForFeatureExtraction.from_pretrained(
            model_name, export=True)
    elapsed = (time.time() - start) * 1000
    return round(elapsed, 1)

def benchmark_inference(encode_fn, text, n_runs=50):
    # Warmup
    for _ in range(5):
        encode_fn(text)
    start = time.time()
    for _ in range(n_runs):
        encode_fn(text)
    elapsed = (time.time() - start) / n_runs * 1000
    return round(elapsed, 2)

